#!/usr/bin/env node
// build-import-bundle.js — Concatenates import-engine/ files in load order.
// Run: node build-import-bundle.js
// Outputs: import-engine/bundle.js (loaded by home.html, index.html, stitch.html)

const fs = require('fs');
const path = require('path');

const ROOT = path.join(__dirname, 'import-engine');
const ORDER = [
  'types.js',
  'registry.js',
  'pipeline.js',
  'workerClient.js',
  'classifier/sniffMagic.js',
  'pdf/operatorWalker.js',
  'pdf/textBands.js',
  'pdf/publishers.js',
  'pdf/dmcPageRoles.js',
  'pdf/legendExtractor.js',
  'pdf/gridExtractor.js',
  'pdf/metaExtractor.js',
  'pipeline/assemble.js',
  'pipeline/validate.js',
  'pipeline/materialise.js',
  'strategies/oxsStrategy.js',
  'strategies/jsonStrategy.js',
  'strategies/imageStrategy.js',
  'ui/ImportReviewModal.js',
  'wireApp.js',
  'index.js',
];

const HEADER = `/* import-engine/bundle.js — auto-generated by build-import-bundle.js.
   Do NOT edit directly. */\n`;

const out = [HEADER];
for (const rel of ORDER) {
  const file = path.join(ROOT, rel);
  if (!fs.existsSync(file)) {
    console.warn('  (skip) ' + rel + ' — not found');
    continue;
  }
  const src = fs.readFileSync(file, 'utf8');
  out.push('\n/* ────── ' + rel + ' ────── */\n');
  out.push(src);
}

const dest = path.join(ROOT, 'bundle.js');
fs.writeFileSync(dest, out.join('\n'), 'utf8');
console.log('Wrote ' + dest + ' (' + ORDER.length + ' files)');
